function solve(nums, edges) {
    const N = nums.length;

    // 1. Build Adjacency Matrix
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let validSubsetCount = 0;

    // Iterate over all non-empty subsets (masks from 1 to 2^N - 1)
    const totalMasks = 1 << N;
    for (let mask = 1; mask < totalMasks; mask++) {

        let subsetSum = 0;
        let subsetSize = 0;
        let nodesInSubset = [];

        // Determine subset properties and list nodes
        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                subsetSum += nums[i];
                subsetSize++;
                nodesInSubset.push(i);
            }
        }

        // 3a. Check Sum Parity
        if (subsetSum % 2 !== 0) {
            continue;
        }

        // 3b. Check Connectivity
        if (subsetSize === 0) {
            // Should not happen as mask starts at 1
            continue;
        }

        if (subsetSize === 1) {
            // Single node subset is always connected
            validSubsetCount++;
            continue;
        }

        // Start BFS/DFS from the first node in the subset
        const startNode = nodesInSubset[0];

        const visited = new Array(N).fill(false);
        const queue = [startNode];
        visited[startNode] = true;
        let reachableCount = 0;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];
            reachableCount++;

            // Check neighbors of u
            for (let v = 0; v < N; v++) {
                // 1. Is there an edge between u and v?
                // 2. Is v part of the subset (mask)?
                // 3. Has v not been visited yet?
                if (adj[u][v] && ((mask >> v) & 1) && !visited[v]) {
                    visited[v] = true;
                    queue.push(v);
                }
            }
        }

        // If the number of reachable nodes equals the total size of the subset, it is connected.
        if (reachableCount === subsetSize) {
            validSubsetCount++;
        }
    }

    return validSubsetCount;
}

